  ('aboriginal-f0899a01-moex-00187', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '刑法有關數人犯罪之處罰規定，下列敘述何者錯誤？', '["在公共場所聚集3人以上共同犯妨害公務者，成立第136條聚眾妨害公務罪", "2人以上共同犯強制性交罪者，成立第222條加重強制性交罪", "結夥3人以上共同犯竊盜罪者，成立第321條加重竊盜罪", "2人以上共同犯詐欺取財罪者，成立第339條之4加重詐欺罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00188', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '依刑法第57條之規定，法官於科刑時，應以下列何種事由為基礎，並審酌一切情狀？', '["以行為人之責任為基礎", "以行為人之學歷為基礎", "以行為人之素行為基礎", "以行為人之經濟能力為基礎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00189', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關刑法緩刑之敘述，下列何者錯誤？', '["依刑法之規定，緩刑之撤銷可分為應撤銷緩刑與得撤銷緩刑二種類型", "緩刑宣告得命犯罪行為人向被害人支付相當數額之損害賠償", "緩刑宣告得命犯罪行為人向公庫支付一定之金額", "緩刑前因故意犯他罪，而在緩刑期內受1年有期徒刑之宣告確定者，為得撤銷緩刑之事由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00190', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於有期徒刑之敘述，下列何者錯誤？', '["無減輕事由時，不得低於2個月", "無加重事由時，不能超過15年", "遇有加重事由時，得加至40年以上", "遇有減輕事由時，得減至2個月未滿"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00191', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關刑法繼續犯之追訴權時效起算之規定，下列何者正確？', '["自犯罪未遂之日起", "自犯罪既遂之日起", "自犯罪成立之日起", "自行為終了之日起"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00192', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '警員甲在取締違法攤商乙時，看不慣的路人丙不斷推擠甲，以阻止甲取締，但甲的取締行為未受 影響仍順利完成；丙因涉嫌觸犯刑法第135條妨害公務罪而遭甲當場逮捕。有關此情形，下列敘述 何者正確？', '["丙非遭甲取締的對象，故不能成為妨害公務罪的行為人", "甲的取締未受丙阻擋的影響，故丙成立妨害公務罪之未遂犯", "丙推擠甲之行為，屬妨害公務罪之強暴行為", "乙未阻止丙之行為，成立妨害公務罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00193', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '公務員乙在某房子門柱上黏貼拆除違建公函，尚未黏貼完成，即遭屋主甲撕下、揉搓並丟擲乙，並揮 打乙，致乙唇內破皮紅腫，下列敘述何者錯誤？', '["甲成立刑法第135條妨害公務罪", "甲成立刑法第138條妨害公務員職務上掌管文書罪", "甲成立刑法第277條傷害罪", "甲成立刑法第150條妨害秩序罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00194', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲妻協助遭依法逮捕之乙夫從看守所脫逃，甲之刑事責任為何？', '["不成立犯罪", "成立刑法第162條之便利脫逃罪", "成立刑法第164條之藏匿人犯罪", "成立刑法第165條隱匿他人刑事證據罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00195', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關枉法裁判罪之罪質，下列何者正確？', '["純正身分犯", "集合犯", "實害犯", "繼續犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00196', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '刑法第165條規定：「偽造、變造、湮滅或隱匿關係他人刑事被告案件之證據，或使用偽造、變造之證 據者，處二年以下有期徒刑、拘役或一萬五千元以下罰金。」關於湮滅證據罪，下列敘述何者錯誤？', '["湮滅自己為刑事被告犯罪之證據，不構成湮滅證據罪", "所謂「刑事被告案件之證據」，依實務見解，不包括尚未開始偵查程序之案件的證據", "本罪所謂「證據」，只限於物證，不包括書證", "湮滅有關他人民事訴訟事件之證據，不構成本罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
